import java.util.*;

public class HighestSharedDivisor {

    /**
     * Method to find the highest shared divisor between two numbers.
     * @param a First number
     * @param b Second number
     * @return The highest shared divisor, or -1 if no common divisor exists
     */
    public static int findHighestSharedDivisor(int a, int b) {
        if (a <= 0 || b <= 0) {
            return -1;
        }

        Set<Integer> divisorsOfA = getDivisors(a);
        Set<Integer> divisorsOfB = getDivisors(b);

        Set<Integer> commonDivisors = new HashSet<>(divisorsOfA);
        commonDivisors.retainAll(divisorsOfB);

        if (commonDivisors.isEmpty()) {
            return -1;
        }

        return Collections.max(commonDivisors);
    }

    /**
     * Helper method to get all divisors of a number.
     * @param number The number to find divisors for
     * @return A set of divisors of the number
     */
    private static Set<Integer> getDivisors(int number) {
        Set<Integer> divisors = new HashSet<>();
        for (int i = 1; i <= Math.sqrt(number); i++) {
            if (number % i == 0) {
                divisors.add(i);
                divisors.add(number / i);
            }
        }
        return divisors;
    }

    /**
     * Main method to test the HighestSharedDivisor algorithm.
     * @param args Command line arguments
     */
    public static void main(String[] args) {
        int a = 12;
        int b = 18;
        int result = findHighestSharedDivisor(a, b);
        System.out.println("Highest shared divisor of " + a + " and " + b + " is: " + result);
    }
}
