    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`Failed to fetch current weather for ${city}`);
    }

    const data = await response.json();
    return {
      city: data.name,
      temperature: data.main.temp,
      humidity: data.main.humidity,
      windSpeed: data.wind.speed,
      weatherDescription: data.weather[0].description
    };
  } catch (error) {
    console.error("Error fetching current weather:", error);
    return null;
  }
}

// Function to fetch five-day forecast for a given city
async function getFiveDayForecast(city) {
  try {
    const currentWeather = await getCurrentWeather(city);
    if (!currentWeather) {
      throw new Error(`No current weather data available for ${city}`);
    }

    // API endpoint for five-day forecast
    const forecastUrl = `https://api.openweathermap.org/data/2.5/forecast?q=${city}&appid=YOUR_API_KEY&units=metric`;

